const express = require('express');
const {
  generateRegistrationOptions,
  verifyRegistrationResponse,
  generateAuthenticationOptions,
  verifyAuthenticationResponse
} = require('@simplewebauthn/server');
const { isoBase64URL } = require('@simplewebauthn/server/helpers');

const app = express();
app.use(express.json());

// Configuration
const rpName = 'Ansvar Security Platform';
const rpID = 'app.ansvar.com';
const origin = `https://${rpID}`;

// In-memory store (use database in production)
const users = new Map();
const challenges = new Map();

// 1. Registration: Generate options for new hardware key
app.post('/auth/webauthn/register/options', async (req, res) => {
  const { userId, username, email } = req.session.user;

  // Get user's existing authenticators from database
  const user = users.get(userId) || { 
    id: userId, 
    username, 
    email,
    authenticators: [] 
  };

  const options = await generateRegistrationOptions({
    rpName,
    rpID,
    userID: userId,
    userName: username,
    userDisplayName: email,
    // Require resident key for passwordless authentication
    authenticatorSelection: {
      authenticatorAttachment: 'cross-platform', // USB keys
      residentKey: 'required',
      userVerification: 'required'
    },
    // Exclude already registered authenticators
    excludeCredentials: user.authenticators.map(auth => ({
      id: auth.credentialID,
      type: 'public-key',
      transports: auth.transports
    })),
    attestationType: 'none'
  });

  // Store challenge for verification
  challenges.set(userId, options.challenge);

  res.json(options);
});

// 2. Registration: Verify hardware key registration
app.post('/auth/webauthn/register/verify', async (req, res) => {
  const { userId } = req.session.user;
  const { credential } = req.body;

  const expectedChallenge = challenges.get(userId);
  if (!expectedChallenge) {
    return res.status(400).json({ error: 'Challenge expired or not found' });
  }

  try {
    const verification = await verifyRegistrationResponse({
      response: credential,
      expectedChallenge,
      expectedOrigin: origin,
      expectedRPID: rpID,
      requireUserVerification: true
    });

    const { verified, registrationInfo } = verification;

    if (!verified || !registrationInfo) {
      return res.status(400).json({ error: 'Registration verification failed' });
    }

    const { credentialPublicKey, credentialID, counter } = registrationInfo;

    // Store authenticator in database
    const user = users.get(userId) || { 
      id: userId, 
      authenticators: [] 
    };

    const newAuthenticator = {
      credentialID: isoBase64URL.fromBuffer(credentialID),
      credentialPublicKey: isoBase64URL.fromBuffer(credentialPublicKey),
      counter,
      transports: credential.response.transports || ['usb'],
      registeredAt: new Date().toISOString()
    };

    user.authenticators.push(newAuthenticator);
    users.set(userId, user);

    // Clear challenge
    challenges.delete(userId);

    // Disable backup codes when hardware key is registered
    await disableBackupCodes(userId);

    res.json({ 
      verified: true,
      message: 'Hardware security key registered successfully. Backup codes have been disabled.' 
    });

  } catch (error) {
    console.error('WebAuthn registration error:', error);
    res.status(500).json({ error: 'Registration failed' });
  }
});

// 3. Authentication: Generate challenge for hardware key
app.post('/auth/webauthn/authenticate/options', async (req, res) => {
  const { username } = req.body;

  // Find user and their authenticators
  const user = Array.from(users.values()).find(u => u.username === username);

  if (!user || !user.authenticators.length) {
    return res.status(404).json({ error: 'No hardware keys registered for this user' });
  }

  const options = await generateAuthenticationOptions({
    rpID,
    allowCredentials: user.authenticators.map(auth => ({
      id: isoBase64URL.toBuffer(auth.credentialID),
      type: 'public-key',
      transports: auth.transports
    })),
    userVerification: 'required'
  });

  // Store challenge
  challenges.set(user.id, options.challenge);

  res.json(options);
});

// 4. Authentication: Verify hardware key assertion
app.post('/auth/webauthn/authenticate/verify', async (req, res) => {
  const { username, credential } = req.body;

  const user = Array.from(users.values()).find(u => u.username === username);
  if (!user) {
    return res.status(404).json({ error: 'User not found' });
  }

  const expectedChallenge = challenges.get(user.id);
  if (!expectedChallenge) {
    return res.status(400).json({ error: 'Challenge expired' });
  }

  // Find the authenticator being used
  const credentialIDBuffer = isoBase64URL.toBuffer(credential.id);
  const authenticator = user.authenticators.find(auth => 
    auth.credentialID === isoBase64URL.fromBuffer(credentialIDBuffer)
  );

  if (!authenticator) {
    return res.status(400).json({ error: 'Authenticator not registered' });
  }

  try {
    const verification = await verifyAuthenticationResponse({
      response: credential,
      expectedChallenge,
      expectedOrigin: origin,
      expectedRPID: rpID,
      authenticator: {
        credentialID: isoBase64URL.toBuffer(authenticator.credentialID),
        credentialPublicKey: isoBase64URL.toBuffer(authenticator.credentialPublicKey),
        counter: authenticator.counter
      },
      requireUserVerification: true
    });

    const { verified, authenticationInfo } = verification;

    if (!verified) {
      return res.status(400).json({ error: 'Authentication verification failed' });
    }

    // Update counter
    authenticator.counter = authenticationInfo.newCounter;
    users.set(user.id, user);

    // Clear challenge
    challenges.delete(user.id);

    // Create session
    req.session.user = {
      userId: user.id,
      username: user.username,
      email: user.email,
      mfaVerified: true,
      authMethod: 'webauthn'
    };

    res.json({ 
      verified: true,
      message: 'Authentication successful' 
    });

  } catch (error) {
    console.error('WebAuthn authentication error:', error);
    res.status(500).json({ error: 'Authentication failed' });
  }
});

function disableBackupCodes(userId) {
  // Disable backup codes in database when hardware key is active
  // Implementation depends on your database schema
  return Promise.resolve();
}

app.listen(3000, () => {
  console.log('WebAuthn server running on port 3000');
});

package com.ansvar.security.mfa;

import org.springframework.security.crypto.argon2.Argon2PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import jakarta.servlet.http.HttpServletRequest;
import java.security.SecureRandom;
import java.time.LocalDateTime;
import java.time.temporal.ChronoUnit;
import java.util.*;
import java.util.stream.Collectors;

@Service
public class BackupCodeService {

    private final BackupCodeRepository backupCodeRepository;
    private final UserRepository userRepository;
    private final NotificationService notificationService;
    private final AuditLogService auditLogService;
    private final Argon2PasswordEncoder passwordEncoder;
    private final RateLimitService rateLimitService;

    private static final int CODE_LENGTH = 10;
    private static final int CODE_COUNT = 10;
    private static final int MAX_ATTEMPTS_PER_HOUR = 3;
    private static final String CHARACTERS = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";

    public BackupCodeService(
            BackupCodeRepository backupCodeRepository,
            UserRepository userRepository,
            NotificationService notificationService,
            AuditLogService auditLogService) {
        this.backupCodeRepository = backupCodeRepository;
        this.userRepository = userRepository;
        this.notificationService = notificationService;
        this.auditLogService = auditLogService;
        // Argon2 with secure parameters for backup code hashing
        this.passwordEncoder = new Argon2PasswordEncoder(
            16,    // salt length
            32,    // hash length
            1,     // parallelism
            65536, // memory (64 MB)
            3      // iterations
        );
        this.rateLimitService = new RateLimitService();
    }

    /**
     * Generate new backup codes for a user
     * IMPORTANT: Only call when user has verified their primary MFA
     */
    @Transactional
    public BackupCodeGenerationResult generateBackupCodes(Long userId) {
        User user = userRepository.findById(userId)
            .orElseThrow(() -> new UserNotFoundException("User not found"));

        // Invalidate all existing backup codes
        backupCodeRepository.invalidateAllForUser(userId);

        SecureRandom random = new SecureRandom();
        List<String> plaintextCodes = new ArrayList<>();
        List<BackupCode> backupCodes = new ArrayList<>();

        for (int i = 0; i < CODE_COUNT; i++) {
            // Generate cryptographically secure random code
            String code = generateSecureCode(random);
            plaintextCodes.add(code);

            // Hash code before storing (NEVER store plaintext)
            String hashedCode = passwordEncoder.encode(code);

            BackupCode backupCode = BackupCode.builder()
                .userId(userId)
                .codeHash(hashedCode)
                .createdAt(LocalDateTime.now())
                .expiresAt(LocalDateTime.now().plusMonths(6))
                .used(false)
                .usedAt(null)
                .usedFromIp(null)
                .usedFromDeviceFingerprint(null)
                .build();

            backupCodes.add(backupCode);
        }

        backupCodeRepository.saveAll(backupCodes);

        auditLogService.log(
            AuditEvent.BACKUP_CODES_GENERATED,
            userId,
            Map.of("count", CODE_COUNT)
        );

        // Send notification to user
        notificationService.sendEmail(
            user.getEmail(),
            "New Backup Codes Generated",
            "New MFA backup codes have been generated for your account. " +
            "If you did not request this, please contact security immediately."
        );

        // Return plaintext codes ONLY once for user to save
        return new BackupCodeGenerationResult(plaintextCodes);
    }

    /**
     * Validate a backup code with comprehensive security controls
     */
    @Transactional
    public BackupCodeValidationResult validateBackupCode(
            Long userId, 
            String code, 
            HttpServletRequest request) {

        User user = userRepository.findById(userId)
            .orElseThrow(() -> new UserNotFoundException("User not found"));

        String ipAddress = getClientIP(request);
        String deviceFingerprint = extractDeviceFingerprint(request);

        // 1. Rate limiting - prevent brute force
        String rateLimitKey = String.format("backup_code_attempt:%d:%s", userId, ipAddress);
        if (!rateLimitService.checkRateLimit(rateLimitKey, MAX_ATTEMPTS_PER_HOUR, 1, ChronoUnit.HOURS)) {
            auditLogService.log(
                AuditEvent.BACKUP_CODE_RATE_LIMIT_EXCEEDED,
                userId,
                Map.of("ip", ipAddress)
            );

            notificationService.sendSecurityAlert(
                user.getEmail(),
                "Multiple Failed Backup Code Attempts",
                String.format("Multiple failed backup code attempts detected from IP: %s", ipAddress)
            );

            return BackupCodeValidationResult.rateLimitExceeded();
        }

        // 2. Get active (unused) backup codes for user
        List<BackupCode> activeCodes = backupCodeRepository
            .findActiveByUserId(userId);

        if (activeCodes.isEmpty()) {
            auditLogService.log(
                AuditEvent.BACKUP_CODE_ATTEMPT_NO_ACTIVE_CODES,
                userId,
                Map.of("ip", ipAddress)
            );
            return BackupCodeValidationResult.invalid();
        }

        // 3. Check code against all active backup codes using constant-time comparison
        BackupCode matchedCode = null;
        for (BackupCode backupCode : activeCodes) {
            // Check expiration
            if (backupCode.getExpiresAt().isBefore(LocalDateTime.now())) {
                continue;
            }

            // Argon2 verify (constant-time comparison)
            if (passwordEncoder.matches(code, backupCode.getCodeHash())) {
                matchedCode = backupCode;
                break;
            }
        }

        if (matchedCode == null) {
            auditLogService.log(
                AuditEvent.BACKUP_CODE_VALIDATION_FAILED,
                userId,
                Map.of("ip", ipAddress, "deviceFingerprint", deviceFingerprint)
            );
            return BackupCodeValidationResult.invalid();
        }

        // 4. IP-based anomaly detection
        List<String> knownIPs = user.getKnownIpAddresses();
        boolean suspiciousIP = !knownIPs.contains(ipAddress);

        // 5. Device fingerprint check
        List<String> knownDevices = user.getKnownDeviceFingerprints();
        boolean suspiciousDevice = !knownDevices.contains(deviceFingerprint);

        // 6. Mark code as used (one-time use enforcement)
        matchedCode.setUsed(true);
        matchedCode.setUsedAt(LocalDateTime.now());
        matchedCode.setUsedFromIp(ipAddress);
        matchedCode.setUsedFromDeviceFingerprint(deviceFingerprint);
        backupCodeRepository.save(matchedCode);

        // 7. Check remaining codes
        long remainingCodes = backupCodeRepository.countActiveByUserId(userId);

        // 8. Audit logging with full context
        auditLogService.log(
            AuditEvent.BACKUP_CODE_USED,
            userId,
            Map.of(
                "ip", ipAddress,
                "deviceFingerprint", deviceFingerprint,
                "suspiciousIP", suspiciousIP,
                "suspiciousDevice", suspiciousDevice,
                "remainingCodes", remainingCodes
            )
        );

        // 9. Send immediate notification to user
        notificationService.sendSecurityAlert(
            user.getEmail(),
            "Backup Code Used for Authentication",
            String.format(
                "A backup code was used to access your account.\n\n" +
                "Time: %s\n" +
                "IP Address: %s\n" +
                "Device: %s\n" +
                "Remaining codes: %d\n\n" +
                "If this wasn't you, secure your account immediately.",
                LocalDateTime.now(),
                ipAddress,
                deviceFingerprint,
                remainingCodes
            )
        );

        // 10. Trigger re-generation if running low
        if (remainingCodes <= 2) {
            notificationService.sendEmail(
                user.getEmail(),
                "Low Backup Code Count",
                "You have " + remainingCodes + " backup codes remaining. " +
                "Please generate new codes to maintain account recovery options."
            );
        }

        return BackupCodeValidationResult.success(
            remainingCodes,
            suspiciousIP,
            suspiciousDevice
        );
    }

    private String generateSecureCode(SecureRandom random) {
        StringBuilder code = new StringBuilder(CODE_LENGTH);
        for (int i = 0; i < CODE_LENGTH; i++) {
            code.append(CHARACTERS.charAt(random.nextInt(CHARACTERS.length())));
        }
        // Format as XXXXX-XXXXX for readability
        return code.substring(0, 5) + "-" + code.substring(5);
    }

    private String getClientIP(HttpServletRequest request) {
        String[] headers = {
            "X-Forwarded-For",
            "X-Real-IP",
            "Proxy-Client-IP",
            "WL-Proxy-Client-IP"
        };

        for (String header : headers) {
            String ip = request.getHeader(header);
            if (ip != null && !ip.isEmpty() && !"unknown".equalsIgnoreCase(ip)) {
                // X-Forwarded-For can contain multiple IPs
                return ip.split(",")[0].trim();
            }
        }

        return request.getRemoteAddr();
    }

    private String extractDeviceFingerprint(HttpServletRequest request) {
        // Combine User-Agent, Accept-Language, and custom fingerprint header
        String userAgent = request.getHeader("User-Agent");
        String acceptLanguage = request.getHeader("Accept-Language");
        String customFingerprint = request.getHeader("X-Device-Fingerprint");

        if (customFingerprint != null && !customFingerprint.isEmpty()) {
            return customFingerprint;
        }

        // Fallback to basic fingerprint
        return Base64.getEncoder().encodeToString(
            (userAgent + "|" + acceptLanguage).getBytes()
        );
    }
}

const express = require('express');
const speakeasy = require('speakeasy');
const QRCode = require('qrcode');
const crypto = require('crypto');
const DeviceDetector = require('device-detector-js');
const geoip = require('geoip-lite');

const app = express();
app.use(express.json());

const deviceDetector = new DeviceDetector();

// Database models (use your actual ORM)
const db = {
  users: new Map(),
  sessions: new Map(),
  deviceBindings: new Map()
};

/**
 * Generate TOTP secret and bind to device
 */
app.post('/auth/totp/setup', async (req, res) => {
  const { userId } = req.session;
  const deviceInfo = extractDeviceInfo(req);

  // Generate unique TOTP secret
  const secret = speakeasy.generateSecret({
    name: `Ansvar Security (${req.session.user.email})`,
    issuer: 'Ansvar',
    length: 32 // 256-bit secret
  });

  // Create device binding fingerprint
  const deviceFingerprint = generateDeviceFingerprint(deviceInfo);

  // Store TOTP secret with device binding
  const user = db.users.get(userId);
  user.totp = {
    secret: secret.base32,
    tempSecret: secret.base32, // Temporary until verified
    verified: false,
    deviceFingerprint,
    deviceInfo: {
      userAgent: deviceInfo.userAgent,
      browser: deviceInfo.browser,
      os: deviceInfo.os,
      device: deviceInfo.device,
      registeredAt: new Date().toISOString(),
      lastUsedAt: null,
      ipAddress: deviceInfo.ipAddress,
      location: deviceInfo.location
    }
  };

  db.users.set(userId, user);

  // Generate QR code for authenticator app
  const qrCodeUrl = await QRCode.toDataURL(secret.otpauth_url);

  res.json({
    secret: secret.base32,
    qrCode: qrCodeUrl,
    otpauthUrl: secret.otpauth_url,
    deviceBound: true,
    message: 'TOTP will be bound to this device. Scan QR code with authenticator app.'
  });
});

/**
 * Verify TOTP setup and finalize device binding
 */
app.post('/auth/totp/verify-setup', async (req, res) => {
  const { userId } = req.session;
  const { token } = req.body;
  const deviceInfo = extractDeviceInfo(req);

  const user = db.users.get(userId);
  if (!user.totp || user.totp.verified) {
    return res.status(400).json({ error: 'TOTP already verified or not initialized' });
  }

  // Verify the token
  const verified = speakeasy.totp.verify({
    secret: user.totp.tempSecret,
    encoding: 'base32',
    token,
    window: 1 // Allow 1 time step before/after for clock skew
  });

  if (!verified) {
    return res.status(400).json({ error: 'Invalid TOTP token' });
  }

  // Confirm device binding matches
  const currentFingerprint = generateDeviceFingerprint(deviceInfo);
  if (currentFingerprint !== user.totp.deviceFingerprint) {
    return res.status(403).json({ 
      error: 'Device mismatch. TOTP must be verified from the same device it was set up on.' 
    });
  }

  // Finalize TOTP setup
  user.totp.verified = true;
  user.totp.secret = user.totp.tempSecret;
  delete user.totp.tempSecret;
  user.totp.deviceInfo.lastUsedAt = new Date().toISOString();

  // Generate backup codes with restrictions
  const backupCodes = generateRestrictedBackupCodes(userId);

  db.users.set(userId, user);

  // Audit log
  await auditLog({
    event: 'TOTP_ENABLED',
    userId,
    deviceInfo,
    timestamp: new Date()
  });

  res.json({
    verified: true,
    backupCodes: backupCodes.codes,
    backupCodeRestrictions: {
      requiresStepUp: true,
      limitedOperations: true,
      forcesReenrollment: true,
      message: 'Backup codes can only be used once and will require MFA re-enrollment after use'
    }
  });
});

/**
 * Authenticate with TOTP (with device binding check)
 */
app.post('/auth/totp/verify', async (req, res) => {
  const { username, password, token } = req.body;
  const deviceInfo = extractDeviceInfo(req);

  // 1. Verify username/password
  const user = Array.from(db.users.values()).find(u => u.username === username);
  if (!user || !verifyPassword(password, user.passwordHash)) {
    return res.status(401).json({ error: 'Invalid credentials' });
  }

  if (!user.totp || !user.totp.verified) {
    return res.status(400).json({ error: 'TOTP not enabled for this user' });
  }

  // 2. Check device binding
  const currentFingerprint = generateDeviceFingerprint(deviceInfo);
  const deviceMismatch = currentFingerprint !== user.totp.deviceFingerprint;

  if (deviceMismatch) {
    // Log suspicious activity
    await auditLog({
      event: 'TOTP_DEVICE_MISMATCH',
      userId: user.id,
      expected: user.totp.deviceInfo,
      actual: deviceInfo,
      timestamp: new Date()
    });

    // Send security alert
    await sendSecurityAlert(user, {
      subject: 'TOTP Authentication from Unrecognized Device',
      message: `An attempt was made to use your TOTP code from a different device.\n\n` +
               `Expected: ${user.totp.deviceInfo.browser} on ${user.totp.deviceInfo.os}\n` +
               `Actual: ${deviceInfo.browser} on ${deviceInfo.os}\n` +
               `IP: ${deviceInfo.ipAddress}\n` +
               `Location: ${deviceInfo.location}`
    });

    return res.status(403).json({ 
      error: 'Device mismatch detected. Please use backup code or contact support.',
      allowBackupCode: true
    });
  }

  // 3. Verify TOTP token
  const verified = speakeasy.totp.verify({
    secret: user.totp.secret,
    encoding: 'base32',
    token,
    window: 1
  });

  if (!verified) {
    await auditLog({
      event: 'TOTP_VERIFICATION_FAILED',
      userId: user.id,
      deviceInfo,
      timestamp: new Date()
    });

    return res.status(400).json({ error: 'Invalid TOTP token' });
  }

  // 4. Update device last used
  user.totp.deviceInfo.lastUsedAt = new Date().toISOString();
  db.users.set(user.id, user);

  // 5. Create authenticated session
  req.session.user = {
    userId: user.id,
    username: user.username,
    mfaVerified: true,
    mfaMethod: 'totp',
    deviceFingerprint: currentFingerprint
  };

  await auditLog({
    event: 'TOTP_AUTHENTICATION_SUCCESS',
    userId: user.id,
    deviceInfo,
    timestamp: new Date()
  });

  res.json({ 
    success: true,
    message: 'Authentication successful' 
  });
});

/**
 * Use backup code with step-up authentication and re-enrollment
 */
app.post('/auth/backup-code/verify', async (req, res) => {
  const { username, password, backupCode } = req.body;
  const deviceInfo = extractDeviceInfo(req);

  const user = Array.from(db.users.values()).find(u => u.username === username);
  if (!user || !verifyPassword(password, user.passwordHash)) {
    return res.status(401).json({ error: 'Invalid credentials' });
  }

  // Find and verify backup code
  const codeIndex = user.backupCodes?.findIndex(bc => 
    bc.code === hashBackupCode(backupCode) && !bc.used
  );

  if (codeIndex === -1) {
    return res.status(400).json({ error: 'Invalid or used backup code' });
  }

  // Mark code as used
  user.backupCodes[codeIndex].used = true;
  user.backupCodes[codeIndex].usedAt = new Date().toISOString();
  user.backupCodes[codeIndex].usedFromIp = deviceInfo.ipAddress;

  // Clear TOTP - force re-enrollment
  const previousTotp = user.totp;
  user.totp = null;

  db.users.set(user.id, user);

  // Send security alert
  await sendSecurityAlert(user, {
    subject: 'Backup Code Used - MFA Re-enrollment Required',
    message: `A backup code was used to access your account. For security, you must re-enroll in MFA.\n\n` +
             `Time: ${new Date().toISOString()}\n` +
             `IP: ${deviceInfo.ipAddress}\n` +
             `Location: ${deviceInfo.location}`
  });

  await auditLog({
    event: 'BACKUP_CODE_USED',
    userId: user.id,
    deviceInfo,
    previousMfaMethod: 'totp',
    mfaCleared: true,
    timestamp: new Date()
  });

  // Create limited session requiring MFA re-enrollment
  req.session.user = {
    userId: user.id,
    username: user.username,
    mfaVerified: false,
    requiresMfaReenrollment: true,
    restrictedAccess: true
  };

  res.json({ 
    success: true,
    warning: 'You must re-enroll in MFA to restore full account access',
    requiresMfaReenrollment: true,
    restrictedOperations: ['transfer', 'settings', 'sensitive_data']
  });
});

// Helper functions
function extractDeviceInfo(req) {
  const userAgent = req.headers['user-agent'];
  const device = deviceDetector.parse(userAgent);
  const ipAddress = req.ip || req.connection.remoteAddress;
  const geo = geoip.lookup(ipAddress);

  return {
    userAgent,
    browser: device.client?.name || 'Unknown',
    browserVersion: device.client?.version || 'Unknown',
    os: device.os?.name || 'Unknown',
    osVersion: device.os?.version || 'Unknown',
    device: device.device?.type || 'desktop',
    ipAddress,
    location: geo ? `${geo.city}, ${geo.country}` : 'Unknown'
  };
}

function generateDeviceFingerprint(deviceInfo) {
  const fingerprintData = [
    deviceInfo.browser,
    deviceInfo.os,
    deviceInfo.device,
    deviceInfo.userAgent
  ].join('|');

  return crypto
    .createHash('sha256')
    .update(fingerprintData)
    .digest('hex');
}

function generateRestrictedBackupCodes(userId) {
  const codes = [];
  const hashedCodes = [];

  for (let i = 0; i < 10; i++) {
    const code = crypto.randomBytes(8).toString('hex').toUpperCase();
    codes.push(code);
    hashedCodes.push({
      code: hashBackupCode(code),
      used: false,
      createdAt: new Date().toISOString()
    });
  }

  const user = db.users.get(userId);
  user.backupCodes = hashedCodes;
  db.users.set(userId, user);

  return { codes, restrictions: true };
}

function hashBackupCode(code) {
  return crypto
    .createHash('sha256')
    .update(code)
