// Detect suspicious backup code usage patterns
let BackupCodeEvents = SecurityEvents
| where EventType == "BackupCodeValidation"
| extend UserId = tostring(UserId), IP = tostring(ClientIP), Result = tostring(Result);
// Multiple failed attempts
let FailedAttempts = BackupCodeEvents
| where Result == "Failed"
| summarize FailedCount = count(), IPs = make_set(IP) by UserId, bin(TimeGenerated, 5m)
| where FailedCount >= 3;
// Backup code use from new location
let UnusualLocation = BackupCodeEvents
| where Result == "Success"
| join kind=leftanti (
    SecurityEvents
    | where EventType in ("Login", "MFASuccess")
    | summarize by UserId, ClientIP
  ) on UserId, $left.IP == $right.ClientIP
| project TimeGenerated, UserId, IP, Message = "Backup code used from new IP";
// Multiple backup codes used rapidly
let RapidUse = BackupCodeEvents
| where Result == "Success"
| summarize CodeCount = count() by UserId, bin(TimeGenerated, 1h)
| where CodeCount >= 3
| project TimeGenerated, UserId, CodeCount, Message = "Multiple backup codes used in short time";
// Combine alerts
union FailedAttempts, UnusualLocation, RapidUse
| order by TimeGenerated desc
